# app/config_loader.py
# In the preview environment, reads prompt and model config from the ConfigMap
# injected by CI — always reflects the PR branch state.

import os, yaml
from functools import lru_cache

CONFIG_DIR = os.environ.get("CONFIG_DIR", "/etc/genai/config")

@lru_cache(maxsize=1)
def load_model_config() -> dict:
    path = os.path.join(CONFIG_DIR, "model_config")
    with open(path) as f:
        return yaml.safe_load(f)

@lru_cache(maxsize=1)
def load_prompt_config() -> dict:
    path = os.path.join(CONFIG_DIR, "prompt_config")
    with open(path) as f:
        return yaml.safe_load(f)

def get_git_sha() -> str:
    path = os.path.join(CONFIG_DIR, "git_sha")
    try:
        return open(path).read().strip()
    except FileNotFoundError:
        return "unknown"

// Included inline in the actions/github-script step above.
// Standalone version for reference — using Octokit directly:

const { Octokit } = require("@octokit/rest");
const octokit = new Octokit({ auth: process.env.GITHUB_TOKEN });

const MARKER = "<!-- preview-env-comment -->";

async function upsertPreviewComment(owner, repo, prNumber, previewUrl, sha) {
  const body = [
    MARKER,
    "## Preview Environment",
    "",
    `**URL:** ${previewUrl}`,
    `**Commit:** \`${sha.slice(0, 7)}\``,
    `**Auto-teardown:** 4h after last push, or when PR closes.`,
  ].join("
");

  const { data: comments } = await octokit.rest.issues.listComments({
    owner, repo, issue_number: prNumber,
  });

  const existing = comments.find(
    c => c.user.type === "Bot" && c.body.includes(MARKER)
  );

  if (existing) {
    await octokit.rest.issues.updateComment({
      owner, repo, comment_id: existing.id, body,
    });
    console.log(`Updated comment ${existing.id}`);
  } else {
    const { data } = await octokit.rest.issues.createComment({
      owner, repo, issue_number: prNumber, body,
    });
    console.log(`Created comment ${data.id}`);
  }
}
